import { Component } from '@angular/core';
import { CommonModule } from '@angular/common'; 
import { FormsModule } from '@angular/forms';   

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent {
  // بيانات كروت الخدمات الثلاثة
  services = [
    { title: 'PEDIATRICIANS' },
    { title: 'URANOLOGISTS' },
    { title: 'IMMUNOLOGISTS' }
  ];

  // تكرار مصفوفة الأطباء الـ 12 تلقائياً بنفس توزيع التصميم الشبكي
  doctors = Array(12).fill(null).map((_, index) => ({
    name: `Doctor M${index + 1}`,
    specialty: 'MBBS, MD'
  }));

  // كائن استقبال بيانات فورم المراسلة
  contactData = {
    firstName: '',
    lastName: '',
    mobileNumber: '',
    email: '',
    message: ''
  };

  // دالة الـ Smooth Scrolling المسؤولة عن تحريك الشاشة بسلاسة للقسم المطلوب عند الضغط على أي زر
  scrollToSection(sectionId: string) {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }

  // تفعيل أزرار تسجيل الدخول وإنشاء الحساب بظهور نافذة تنبيهية لتأكيد عملها
  onSignIn() {
    alert('Sign In trigger functionality is active!');
  }

  onRegister() {
    alert('Register trigger functionality is active!');
  }

  onPrevSlide() {
    console.log('Slider dots navigation triggered.');
  }

  onSubmit() {
    if (this.contactData.firstName) {
      alert(`Thank you! Your message has been sent successfully, ${this.contactData.firstName}.`);
      // تفريغ الحقول بعد الإرسال بنجاح
      this.contactData = { firstName: '', lastName: '', mobileNumber: '', email: '', message: '' };
    }
  }
}
